import{_ as e,p as i,q as a,Y as l}from"./framework-aa5c4115.js";const d={},n=l('<h1 id="dom" tabindex="-1"><a class="header-anchor" href="#dom" aria-hidden="true">#</a> DOM</h1><h2 id="dom-简介" tabindex="-1"><a class="header-anchor" href="#dom-简介" aria-hidden="true">#</a> DOM 简介</h2><p>DOM 是 JS 操控 HTML 和 CSS 的桥梁</p><ul><li>==DOM(Document Object Model，文档对象模型)==是 JavaScript 操作 HTML 文档的接口，使文档操作变得非常优雅、简便。</li><li>DOM 最大的特点就是将文档表示为==节点树==。</li></ul><h2 id="节点操作" tabindex="-1"><a class="header-anchor" href="#节点操作" aria-hidden="true">#</a> 节点操作</h2><p>改变元素节点中的内容可以使用两个相关属性：</p><ul><li>innerHTML</li><li>innerText</li></ul><p>innerHTML 属性能以==HTML 语法==设置节点中的内容</p><p>innerText 属性只能以==纯文本的形式==设置节点中的内容</p><p>一些常用的 HTML DOM 方法：</p><ul><li>getElementById(id) - 获取带有指定 id 的节点（元素）</li><li>appendChild(node) - 插入新的子节点（元素）</li><li>removeChild(node) - 删除子节点（元素）</li></ul><p>一些常用的 HTML DOM 属性：</p><ul><li>innerHTML - 节点（元素）的文本值</li><li>parentNode - 节点（元素）的父节点</li><li>childNodes - 节点（元素）的子节点</li><li>attributes - 节点（元素）的属性节点</li></ul><h2 id="事件流" tabindex="-1"><a class="header-anchor" href="#事件流" aria-hidden="true">#</a> 事件流</h2><p>定义：用户与浏览器当前页面的交互过程 三个阶段：捕获阶段、目标阶段、冒泡阶段</p>',15),r=[n];function t(h,o){return i(),a("div",null,r)}const s=e(d,[["render",t],["__file","DOM.html.vue"]]);export{s as default};
